code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Avatar, Tooltip } from 'decantr/components';

code.example:
function PresenceAvatars({ collaborators, maxVisible = 4, onExpand }) {
  const { div, span, button } = tags;
  const visible = collaborators.slice(0, maxVisible);
  const overflow = collaborators.length - maxVisible;

  return div({ class: css('_flex _aic') },
    ...visible.map((user, i) =>
      Tooltip({ content: `${user.name} (${user.status})` },
        div({ 
          class: css('_relative _-ml2'),
          style: `z-index: ${maxVisible - i}`
        },
          Avatar({ 
            src: user.avatar, 
            fallback: user.initials,
            size: 'sm',
            class: css(`_ring2 _ring[${user.color}] _bg[var(--surface)]`)
          }),
          user.status === 'active' ? div({
            class: css('_absolute _bottom0 _right0 _w2 _h2 _rfull _bg[var(--success)] _ring2 _ring[var(--surface)]')
          }) : null
        )
      )
    ),
    overflow > 0 ? button({
      class: css('_flex _aic _jcc _w8 _h8 _rfull _bg[var(--surface-raised)] _border _textsm _fontmedium _-ml2 _hover:bg[var(--surface)]'),
      onclick: onExpand
    }, `+${overflow}`) : null
  );
}

