code.example:
function DetailedPresence({ collaborators }) {
  const { div } = tags;
  const statusColor = (s) => s === 'active' ? 'var(--success)' : s === 'idle' ? 'var(--warning)' : 'var(--text-muted)';

  return div({ class: css('_flex _aic _gap1') },
    ...collaborators.map(user =>
      Tooltip({ content: `${user.name} - ${user.status}` },
        div({ class: css('_relative') },
          Avatar({ 
            src: user.avatar, 
            fallback: user.initials,
            size: 'sm',
            class: css(`_ring2 _ring[${user.color}]`)
          }),
          div({
            class: css('_absolute _bottom0 _right0 _w3 _h3 _rfull _ring2 _ring[var(--surface)]'),
            style: `background: ${statusColor(user.status)}`
          })
        )
      )
    )
  );
}

